class Solution {
    public List<List<String>> findLadders(String beginWord, String endWord, List<String> wordList) {
        Set<String> dict = new HashSet<>(wordList);
        List<List<String>> results = new ArrayList<>();
        if (!dict.contains(endWord)) return results;
        Map<String, List<String>> children = new HashMap<>();
        Set<String> start = new HashSet<>();
        start.add(beginWord);
        bfs(dict, start, endWord, children, false);
        LinkedList<String> path = new LinkedList<>();
        path.add(beginWord);
        dfs(beginWord, endWord, children, path, results);
        return results;
    }
    private boolean bfs(Set<String> dict, Set<String> start, String end, Map<String, List<String>> children, boolean reverse) {
        if (start.isEmpty()) return false;
        if (start.contains(end)) return true;
        if (start.size() > dict.size()) return bfs(dict, dict, end, children, !reverse);
        dict.removeAll(start);
        Set<String> nextLevel = new HashSet<>();
        boolean found = false;
        for (String word : start) {
            char[] arr = word.toCharArray();
            for (int i = 0; i < arr.length; i++) {
                char old = arr[i];
                for (char c = 'a'; c <= 'z'; c++) {
                    if (c == old) continue;
                    arr[i] = c;
                    String target = new String(arr);
                    if (!dict.contains(target)) continue;
                    nextLevel.add(target);
                    String key = reverse ? target : word;
                    String val = reverse ? word : target;
                    children.computeIfAbsent(key, k -> new ArrayList<>()).add(val);
                    if (target.equals(end)) found = true;
                }
                arr[i] = old;
            }
        }
        return found || bfs(dict, nextLevel, end, children, reverse);
    }
    private void dfs(String word, String end, Map<String, List<String>> children, LinkedList<String> path, List<List<String>> results) {
        if (word.equals(end)) {
            results.add(new ArrayList<>(path));
            return;
        }
        if (!children.containsKey(word)) return;
        for (String nxt : children.get(word)) {
            path.add(nxt);
            dfs(nxt, end, children, path, results);
            path.removeLast();
        }
    }
}
